from dataclasses import dataclass, field

@dataclass
class AISystemScope:
    """ISO/IEC 42001 Clause 4.3 — AIMS scope definition for one AI system."""
    system_id: str
    description: str
    deployment_contexts: list[str]       # e.g. ["EU customer support portal"]
    interested_parties: list[str]        # e.g. ["end users", "deployers", "EU DPA"]
    regulatory_obligations: list[str]    # e.g. ["EU AI Act High-Risk", "GDPR Art 22"]
    contractual_obligations: list[str]   # e.g. ["SOC 2 Type II", "ISO 27001"]
    exclusions: list[str] = field(default_factory=list)   # anything explicitly out of scope

    def scope_statement(self) -> str:
        return (
            f"AIMS scope for {self.system_id}: "
            f"deployed in {', '.join(self.deployment_contexts)}. "
            f"Applicable obligations: {'; '.join(self.regulatory_obligations + self.contractual_obligations)}."
        )

@dataclass
class OrganisationalContext:
    """Clause 4.1/4.2 — Internal and external factors affecting the AIMS."""
    internal_factors: list[str]   # e.g. ["ML team maturity", "existing ISO 27001 certification"]
    external_factors: list[str]   # e.g. ["EU AI Act timeline", "customer audit requirements"]
    systems_in_scope: list[AISystemScope]

from enum import Enum
from dataclasses import dataclass
from typing import Literal

class ImpactSeverity(Enum):
    NEGLIGIBLE = 1
    MINOR      = 2
    MODERATE   = 3
    MAJOR      = 4
    SEVERE     = 5

class ImpactLikelihood(Enum):
    RARE       = 1
    UNLIKELY   = 2
    POSSIBLE   = 3
    LIKELY     = 4
    ALMOST_CERTAIN = 5

@dataclass
class ImpactEntry:
    impact_id: str
    harm_type: str              # e.g. "discrimination", "privacy violation", "physical harm"
    affected_group: str         # e.g. "job applicants", "users in minority groups"
    severity: ImpactSeverity
    likelihood: ImpactLikelihood
    mitigation: str
    residual_severity: ImpactSeverity
    residual_likelihood: ImpactLikelihood

    @property
    def inherent_score(self) -> int:
        return self.severity.value * self.likelihood.value

    @property
    def residual_score(self) -> int:
        return self.residual_severity.value * self.residual_likelihood.value

    @property
    def risk_accepted(self) -> bool:
        return self.residual_score <= 6   # organisation-defined threshold

class AIImpactAssessment:
    """Annex A, A.6 — AI Impact Assessment."""

    def __init__(self, system_id: str, version: str, assessor: str):
        self.system_id = system_id
        self.version = version
        self.assessor = assessor
        self.entries: list[ImpactEntry] = []

    def add(self, entry: ImpactEntry) -> None:
        self.entries.append(entry)

    def unacceptable_impacts(self) -> list[ImpactEntry]:
        return [e for e in self.entries if not e.risk_accepted]

    def summary(self) -> dict:
        return {
            "system": self.system_id,
            "version": self.version,
            "total_impacts": len(self.entries),
            "unacceptable": len(self.unacceptable_impacts()),
            "assessment_complete": len(self.unacceptable_impacts()) == 0,
        }
